const orcamento = $json.body || {};
const calc = orcamento.dimensionamento_backup_calculado || {};
const energia_critica = calc.energia_critica_diaria_kwh || 0;

// Parâmetros de cálculo obrigatórios
const dod = 0.80; // Depth of Discharge máximo (80%)
const eficiencia = 0.85; // Eficiência do inversor/sistema híbrido (85%)
const margem_tecnica = 0.25; // Margem técnica de reserva (25%)

// Fórmulas
const bateria_util_kwh = energia_critica;
// Nominal = útil / (DoD * eficiência) * (1 + margem)
const bateria_nominal_kwh = Number((bateria_util_kwh / (dod * eficiencia) * (1 + margem_tecnica)).toFixed(3));

// Capacidade de descarga contínua a 0.5C (padrão de baterias LFP SolaX Triple Power)
const bateria_capacidade_descarga_kw = Number((bateria_nominal_kwh * 0.5).toFixed(3));

const simultanea_kw = calc.potencia_critica_simultanea_kw || 0;
const pendencias_baterias = [];

if (bateria_capacidade_descarga_kw < simultanea_kw) {
  pendencias_baterias.push(`A potência de descarga contínua do banco (${bateria_capacidade_descarga_kw} kW) é menor que a carga simultânea crítica (${simultanea_kw} kW). Risco de sobrecarga e desligamento. Requer aumento do banco de baterias.`);
}

return {
  ...orcamento,
  dimensionamento_backup_calculado: {
    ...calc,
    bateria_util_kwh,
    bateria_nominal_kwh,
    bateria_capacidade_descarga_kw,
    paramentos_calculo: {
      dod_permitido: dod,
      eficiencia_sistema: eficiencia,
      margem_tecnica: margem_tecnica
    },
    pendencias_baterias
  },
  status: 'calculado_baterias'
};
